#include <bits/stdc++.h>
using namespace std;
int f[200005],n,m;
int fa(int x)
{
    if(f[x]==x) return x;
    return f[x]=fa(f[x]);
}
int main()
{
    cin>>n>>m;
    for(int i=1;i<=n;i++) f[i]=i;
    while(m--)
    {
        int op,x,y;
        cin>>op>>x>>y;
        if(op==1)
        {
            int fx=fa(x),fy=fa(y);
            f[fx]=fy;
        }
        else
        {
            int fx=fa(x),fy=fa(y);
            if(fx==fy) cout<<"Y\n";
            else cout<<"N\n";
        }
    }
    return 0;
}
